const BASE_URL = 'http://host.docker.internal:3002';

// Test cases: [label, username, password, expectSuccess]
const cases = [
  { id: 'TC01', label: 'Valid login',         username: 'test',    password: '10086111', expect: true  },
  { id: 'TC02', label: 'Wrong password',       username: 'test',    password: 'wrongpass', expect: false },
  { id: 'TC03', label: 'Wrong username',       username: 'nobody',  password: '10086111', expect: false },
  { id: 'TC04', label: 'Empty username',       username: '',        password: '10086111', expect: false },
  { id: 'TC05', label: 'Empty password',       username: 'test',    password: '',         expect: false },
  { id: 'TC06', label: 'Both empty',           username: '',        password: '',         expect: false },
  { id: 'TC07', label: 'Username with spaces', username: '  test  ',password: '10086111', expect: false },
  { id: 'TC08', label: 'SQL injection attempt',username: "' OR 1=1--",password: "' OR 1=1--", expect: false }
];

return cases.map(c => ({
  json: {
    base_url: BASE_URL.replace(/\/+$/, ''),
    id: c.id,
    label: c.label,
    username: c.username,
    password: c.password,
    expect: c.expect
  }
}));

const all = $input.all();
const body = all[0] ? all[0].json : {};

// Extract session cookie
let setCookie = '';
for (let i = 1; i < all.length; i++) {
  const h = all[i].json;
  if (h && h.headers && h.headers['set-cookie']) { setCookie = h.headers['set-cookie']; break; }
  if (h && h['set-cookie']) { setCookie = h['set-cookie']; break; }
}
if (!setCookie && all[0] && all[0].headers && all[0].headers['set-cookie']) {
  setCookie = all[0].headers['set-cookie'];
}
const cm = setCookie.match(/(session=[^;]+)/);
const sessionCookie = cm ? cm[1] : '';

const actualOk = body.success === true;
const expectedOk = $input.first().json.expect;
const passed = actualOk === expectedOk;

return {
  json: {
    id: $input.first().json.id,
    label: $input.first().json.label,
    username: $input.first().json.username,
    password_masked: $input.first().json.password ? '****' + $input.first().json.password.slice(-2) : '(empty)',
    expected: expectedOk ? 'PASS' : 'FAIL',
    actual: actualOk ? 'PASS' : 'FAIL',
    result: passed ? 'PASSED' : 'FAILED',
    message: body.message || '',
    user: actualOk ? (body.data ? body.data.username : '?') : null,
    cookie: actualOk ? (sessionCookie ? 'OK' : 'MISSING') : null
  }
};

const results = $input.all().map(item => item.json);
const passed = results.filter(r => r.result === 'PASSED').length;
const failed = results.filter(r => r.result === 'FAILED').length;

return {
  json: {
    summary: {
      total: results.length,
      passed: passed,
      failed: failed,
      passRate: (passed / results.length * 100).toFixed(0) + '%'
    },
    details: results
  }
};
